output.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?artist WHERE {
  wd:Q5710090 wdt:P175 ?artist .
}

args.sparql:
SELECT ?artist ?album ?releaseDate WHERE {
  wd:Q12715406 wdt:P1576 ?album .
  ?album wdt:P175 ?artist .
  ?album wdt:P577 ?releaseDate .
  FILTER (isLiteral(?releaseDate))
} ORDER BY ASC(?releaseDate) LIMIT 1
